15	export function processScenario(scenario: any): unknown {
16	  const items = scenario.steps[0].items;
17	
18	  const totalBasePremium = items.reduce(
19	    (sum: number, item: any) => sum + basePremiumFor(item),
20	    0,
21	  );
22	
23	  const firstInsurance = totalBasePremium * FIRST_INSURANCE_RATE;
24	  const premium = totalBasePremium + firstInsurance + PROCESSING_FEE;
